    status_name = String()

#schema
class Branch(SQLAlchemyObjectType):
    class Meta:
        model = BranchCatModel
        interfaces = (relay.Node,)

class BranchesQuery(ObjectType):
    branch = relay.Node.Field(Branch)
    all_branches = CustomConnectionField(Branch, statuses=StatusInputSchema())
    
